import React, { useState, useEffect } from 'react';
import { Trophy, Award, MapPin, Building2 } from 'lucide-react';
import Navbar from '../components/Navbar';
import Sidebar from '../components/Sidebar';
import { useAuth } from '../context/AuthContext';
import api from '../services/api';
import toast from 'react-hot-toast';

const RANK_STYLES = [
  { bg: 'bg-yellow-50 border-yellow-200', text: 'text-yellow-600', medal: '🥇' },
  { bg: 'bg-gray-50 border-gray-200', text: 'text-gray-500', medal: '🥈' },
  { bg: 'bg-orange-50 border-orange-200', text: 'text-orange-500', medal: '🥉' },
];

function LeaderCard({ rank, user, type }) {
  const style = rank <= 3 ? RANK_STYLES[rank - 1] : null;
  return (
    <div
      className={`flex items-center gap-4 p-4 rounded-2xl border transition-all hover:shadow-md ${
        style ? `${style.bg} border` : 'bg-white border-gray-100'
      }`}
    >
      {/* Rank */}
      <div className="w-10 flex-shrink-0 text-center">
        {rank <= 3 ? (
          <span className="text-2xl">{style.medal}</span>
        ) : (
          <span className="text-lg font-black text-gray-400">#{rank}</span>
        )}
      </div>

      {/* Avatar */}
      <div
        className={`w-11 h-11 rounded-full flex-shrink-0 flex items-center justify-center text-white text-lg font-black ${
          type === 'donors'
            ? 'bg-gradient-to-br from-green-400 to-green-600'
            : 'bg-gradient-to-br from-blue-400 to-blue-600'
        }`}
      >
        {user.name?.[0]?.toUpperCase() || 'U'}
      </div>

      {/* Info */}
      <div className="flex-1 min-w-0">
        <p className="font-bold text-gray-800 truncate">{user.name}</p>
        {user.organizationName && (
          <p className="text-xs text-gray-500 flex items-center gap-1 truncate">
            <Building2 className="w-3 h-3" />
            {user.organizationName}
          </p>
        )}
        {user.city && (
          <p className="text-xs text-gray-400 flex items-center gap-1 truncate">
            <MapPin className="w-3 h-3" />
            {user.city}
          </p>
        )}
      </div>

      {/* Points */}
      <div className="text-right flex-shrink-0">
        <p className={`text-xl font-black ${style ? style.text : 'text-gray-600'}`}>
          {user.impactPoints?.toLocaleString()}
        </p>
        <p className="text-xs text-gray-400">points</p>
        <p className="text-xs text-gray-500 mt-0.5">
          {type === 'donors'
            ? `${user.totalDonations || 0} donations`
            : `${user.totalPickups || 0} pickups`}
        </p>
      </div>
    </div>
  );
}

function TopThree({ users, type }) {
  if (users.length === 0) return null;
  const [second, first, third] = [users[1], users[0], users[2]];
  const heights = ['h-28', 'h-36', 'h-24'];

  return (
    <div className="flex items-end justify-center gap-3 mb-8">
      {[second, first, third].map((u, i) => {
        if (!u) return <div key={i} className="w-24" />;
        const medals = ['🥈', '🥇', '🥉'];
        const colors = [
          'from-gray-300 to-gray-400',
          'from-yellow-400 to-yellow-500',
          'from-orange-300 to-orange-400',
        ];
        const barH = heights[i];
        return (
          <div key={u._id} className="flex flex-col items-center gap-2 w-24">
            <div
              className={`w-14 h-14 rounded-full flex items-center justify-center text-white text-xl font-black shadow-lg bg-gradient-to-br ${
                type === 'donors' ? 'from-green-400 to-emerald-600' : 'from-blue-400 to-blue-600'
              }`}
            >
              {u.name?.[0]?.toUpperCase() || 'U'}
            </div>
            <p className="text-xs font-bold text-gray-700 text-center leading-tight truncate w-full">{u.name}</p>
            <p className="text-xs font-black text-gray-600">{u.impactPoints?.toLocaleString()} pts</p>
            <div
              className={`w-full ${barH} rounded-t-xl bg-gradient-to-t ${colors[i]} flex items-center justify-center text-2xl shadow`}
            >
              {medals[i]}
            </div>
          </div>
        );
      })}
    </div>
  );
}

export default function Leaderboard() {
  const { user } = useAuth();
  const [tab, setTab] = useState('donors');
  const [donors, setDonors] = useState([]);
  const [ngos, setNgos] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchLeaderboard();
    // eslint-disable-next-line
  }, []);

  const fetchLeaderboard = async () => {
    setLoading(true);
    try {
      const [dRes, nRes] = await Promise.all([
        api.get('/users/leaderboard?type=donors'),
        api.get('/users/leaderboard?type=ngos'),
      ]);
      setDonors(dRes.data.leaderboard || []);
      setNgos(nRes.data.leaderboard || []);
    } catch (err) {
      toast.error('Failed to load leaderboard');
    } finally {
      setLoading(false);
    }
  };

  const current = tab === 'donors' ? donors : ngos;

  return (
    <div className="flex min-h-screen bg-gray-50">
      {user && <div className="hidden lg:block"><Sidebar /></div>}
      <div className={`flex-1 min-w-0 flex flex-col ${user ? 'lg:ml-64' : ''}`}>
        <div className="lg:hidden"><Navbar /></div>

      <div className="max-w-2xl mx-auto px-4 sm:px-6 py-8">
        {/* Header */}
        <div className="text-center mb-8">
          <div className="flex items-center justify-center gap-2 mb-2">
            <Trophy className="w-8 h-8 text-yellow-500" />
            <h1 className="text-3xl font-black text-gray-800">Leaderboard</h1>
          </div>
          <p className="text-gray-500 text-sm">Celebrating the champions fighting food waste</p>
        </div>

        {/* Tabs */}
        <div className="flex bg-white border border-gray-200 rounded-2xl p-1 mb-6">
          {[
            { id: 'donors', label: '🍲 Top Donors', desc: 'Most food donated' },
            { id: 'ngos', label: '🤝 Top NGOs', desc: 'Most food collected' },
          ].map((t) => (
            <button
              key={t.id}
              onClick={() => setTab(t.id)}
              className={`flex-1 py-2.5 rounded-xl text-sm font-semibold transition-all ${
                tab === t.id
                  ? 'bg-green-600 text-white shadow'
                  : 'text-gray-600 hover:text-gray-800'
              }`}
            >
              {t.label}
            </button>
          ))}
        </div>

        {loading ? (
          <div className="flex items-center justify-center py-20">
            <div className="w-10 h-10 border-4 border-green-500 border-t-transparent rounded-full animate-spin" />
          </div>
        ) : current.length === 0 ? (
          <div className="text-center py-16">
            <Trophy className="w-12 h-12 text-gray-300 mx-auto mb-3" />
            <p className="text-gray-500">No entries yet. Be the first!</p>
          </div>
        ) : (
          <>
            {/* Podium */}
            {current.length >= 1 && <TopThree users={current.slice(0, 3)} type={tab} />}

            {/* Full list */}
            <div className="space-y-3">
              {current.map((u, i) => (
                <LeaderCard key={u._id} rank={i + 1} user={u} type={tab} />
              ))}
            </div>
          </>
